for deno in "docker run --rm denoland/deno:latest" "cargo run --bin deno --"; do
  echo "=== $deno ==="
  $deno eval "$(cat repro.ts)" 2>&1 | grep -E "^(OK:|ERROR:|TIMEOUT)"
done
```

